 17→class LivingWaterManagementService
 18→{
 19→    use TEncrypt;
 20→
 21→    public function startLivingWater(array $input): array
 22→    {
 23→        $staffId = $input['staff_id'];
 24→        $staff = StaffInformationMd::find($staffId);
 25→        if ($staff == null) {
 26→            return ['flag' => false, 'message' => __('my_api.staff_not_exist')];
 27→        }
 28→        // 查看是否有审批中的
 29→        $processExist = StaffLivingWaterMd::where('staff_id', $input['staff_id'])->whereIn('approval_status', StaffLivingWaterMd::LIVING_WATER_APPROVAL_PROCESS_STATUS)->exists();
 30→        if ($processExist) {
 31→            return ['flag' => false, 'message' => __('my_api.living_water_request_in_process')];
 32→        }
 33→        db()->beginTransaction();
 34→        try {
 35→            $staffLivingWater = new StaffLivingWaterMd();
 36→            $staffLivingWater->staff_id = $input['staff_id'];
 37→            $staffLivingWater->staff_status = $staff->status;
 38→            $staffLivingWater->start_user_id = AuthRecord::user()->user_id;
 39→            $staffLivingWater->original_job_id = $staff->job_id;
 40→            $staffLivingWater->original_department_id = $staff->department_id;
 41→//            $staffLivingWater->original_project = $input['original_project'] ?? '';
 42→//            $staffLivingWater->original_project_hash = $input['original_project_hash'] ?? '';
 43→//            $staffLivingWater->project = $input['project'] ?? '';
 44→//            $staffLivingWater->project_hash = $input['project_hash'] ?? '';
 45→            $staffLivingWater->original_direct_supervisor = $input['original_direct_supervisor'] ?? '';
 46→            $staffLivingWater->original_direct_supervisor_hash = $input['original_direct_supervisor_hash'] ?? '';
 47→            $staffLivingWater->original_supervisor = $staff->supervisor_id;
 48→            $staffLivingWater->original_hrbp_id = $staff->hrbp_id;
 49→            $staffLivingWater->job_id = $input['job_id'];
 50→            $staffLivingWater->department_id = $input['department_id'];
 51→            $staffLivingWater->direct_supervisor = $input['direct_supervisor'] ?? '';
 52→            $staffLivingWater->direct_supervisor_hash = $input['direct_supervisor_hash'] ?? '';
 53→            $staffLivingWater->supervisor = $input['supervisor'];
 54→            $staffLivingWater->hrbp_id = $input['hrbp_id'];
 55→            $staffLivingWater->living_water_date = $input['living_water_date'];
 56→            $staffLivingWater->approval_status = StaffLivingWaterMd::STATUS_WAIT_ORIGINAL_SUPERVISOR_APPROVE;
 57→            if (!empty($input['remark'])) {
 58→                $staffLivingWater->remark = $input['remark'];
 59→            }
 60→            $staffLivingWater->created_at = date('Y-m-d H:i:s');
 61→            $staffLivingWater->updated_at = date('Y-m-d H:i:s');
 62→            $flag = $staffLivingWater->save();
 63→
 64→            $flag && StaffManagementOperationMd::create(
 65→                [
 66→                    'staff_id' => $staffLivingWater->staff_id,
 67→                    'cur_status' => $staff->status,
 68→                    'operation_type' => '员工管理操作',
 69→                    'operation' => 'BP发起审批',
 70→                    'operator_id' => AuthRecord::user()->user_id,
 71→                    'operate_time' => date('Y-m-d H:i:s'),
 72→                    'operation_record' => (AuthRecord::user()->nickname ?? '').'发起了活水审批',
 73→                ]
 74→            );
 75→
 76→            // 授权
 77→            setAuthorityToken($input['authorized_token'], $input['staff_id'], $input['authorized_users'], 3456000, 'staff');
 78→            // 存入邮件和id_sign
 79→            if ($flag) {
 80→                $livingWaterId = $staffLivingWater->id;
 81→                LivingWaterMailMd::updateOrCreate(['living_water_id' => $livingWaterId], ['living_water_id' => $livingWaterId, 'mail' => $input['mail']]);
 82→                // 存入已读未读表, 存入待执行表
 83→                CommonAction::app()->recordRead(StaffLifeType::TYPE_LIVING_WATER, $staffLivingWater->id, AuthRecord::user()->user_id, CommonAction::STATUS_READ);
 84→                if ($input['hrbp_id'] != AuthRecord::user()->user_id) {
 85→                    CommonAction::app()->recordRead(StaffLifeType::TYPE_LIVING_WATER, $staffLivingWater->id, $input['hrbp_id'], CommonAction::STATUS_UN_READ);
 86→                }
 87→                CommonAction::app()->recordAction(StaffLifeType::TYPE_LIVING_WATER, $staffLivingWater->id, $staff->supervisor_id, CommonAction::OPERATE_TODO);
 88→            }
 89→            if (!$flag) {
 90→                db()->rollBack();
 91→            } else {
 92→                db()->commit();
 93→            }
 94→        } catch (\Exception $exception) {
 95→            db()->rollBack();
 96→            $flag = false;
 97→        }
 98→        return ['flag' => $flag, 'message' => '', 'id' => $staffLivingWater->id ?? 0];
 99→    }
