101→    public function getBpLivingWaterList(array $input): array
102→    {
103→        $allStaff = $input['all_staff'] ?? 0;
104→        if ($allStaff && !AuthRecord::user()->is_admin) {
105→            $staffIds = StaffLivingWaterMd::pluck('staff_id')->unique()->toArray();
106→            $staffs = StaffInformationMd::whereIn('id', $staffIds)->selectRaw('id,inputer_user_id,department_id,hrbp_id')->get()->toArray();
107→            $staff_ids = array_column(app(\App\Service\StaffService::class)->checkUserStaffPermission($staffs), 'id'); // 检查权限
108→            $input['staff_ids'] = $staff_ids;
109→        }
110→        $sql = $this->getQuery($input);
111→        if ($allStaff) {
112→            $res = $sql->selectRaw('st.*, si.nickname, si.status as staff_status')->distinct()->orderByDesc('st.id')->paginate($input['per_page'] ?? 50)->toArray();
113→            return [
114→                'list' => $res['data'],
115→                'current_page' => $res['current_page'],
116→                'per_page' => $res['per_page'],
117→                'total' => $res['total'],
118→            ];
119→        }
120→        $myCharge = $input['my_charge_staff'] ?? 0;
121→        $readFlag = $input['read_flag'] ?? 0;
122→        $userId = AuthRecord::user()->user_id;
123→        if ($myCharge) {
124→            $res = $sql->where('si.hrbp_id', $userId)->selectRaw('st.*, si.nickname,si.status as staff_status')->distinct()->orderByDesc('st.id')->paginate($input['per_page'] ?? 50)->toArray();
125→            $data = $res['data'];
126→            if ($readFlag) {
127→                $tableIds = array_column($data, 'id');
128→                $readMap = CommonAction::app()->getReadMap(StaffLifeType::TYPE_LIVING_WATER, $userId, $tableIds);
129→                foreach ($data as $k => $v) {
130→                    $data[$k]['is_read'] = $readMap[$v['id']] ?? 1;
131→                }
132→            }
133→            return [
134→                'list' => $data,
135→                'current_page' => $res['current_page'],
136→                'per_page' => $res['per_page'],
137→                'total' => $res['total'],
138→            ];
139→        }
140→        $res = $sql->where('st.created_at', '>=', date('Y-m-d H:i:s', strtotime('-30 days')))
141→            ->whereRaw("( st.original_hrbp_id={$userId} or st.hrbp_id={$userId} ) and si.hrbp_id <> {$userId}")
142→            ->selectRaw('st.*, si.nickname, si.entry_time, si.status as staff_status')->distinct()->orderByDesc('st.id')->get()->toArray();
143→        if ($readFlag) {
144→            $tableIds = array_column($res, 'id');
145→            $readMap = CommonAction::app()->getReadMap(StaffLifeType::TYPE_LIVING_WATER, $userId, $tableIds);
146→            foreach ($res as $k => $v) {
147→                $res[$k]['is_read'] = $readMap[$v['id']] ?? 1;
148→            }
149→        }
150→        $tokens = [];
151→        $res = array_values(array_filter($res, function ($r) use (&$tokens) {
152→            $token = getAuthorityToken(AuthRecord::user()->user_id, $r['staff_id'], 'staff');
153→            $tokens[] = $token;
154→            return $token !== null;
155→        }));
156→        $tokens = array_values(array_unique(array_filter($tokens)));
157→        return ['list' => $res, 'decrypt_config' => ['tokens' => $tokens]];
158→    }
