160→    public function getLivingWaterList(array $input): array
161→    {
162→        $isChecked = $input['is_checked'] ?? 0;
163→        $isAdmin = $input['is_admin'] ?? false;
164→        $userId = $input['supervisor_ids'];
165→        if ($isAdmin && empty($input['approval_status'])) {
166→            if (!$isChecked) {
167→                $input['approval_status'] = [StaffLivingWaterMd::STATUS_NEW_SUPERVISOR_APPROVED];
168→            } else {
169→                $input['approval_status'] = [StaffLivingWaterMd::STATUS_ADMIN_APPROVED, StaffLivingWaterMd::STATUS_ADMIN_REJECT];
170→            }
171→        }
172→        if (!$isAdmin && empty($input['approval_status'])) {
173→            if (!$isChecked) {
174→                $input['approval_status'] = [StaffLivingWaterMd::STATUS_WAIT_ORIGINAL_SUPERVISOR_APPROVE, StaffLivingWaterMd::STATUS_ORIGINAL_SUPERVISOR_APPROVED];
175→            } else {
176→                $input['approval_status'] = [StaffLivingWaterMd::STATUS_ORIGINAL_SUPERVISOR_APPROVED, StaffLivingWaterMd::STATUS_ORIGINAL_SUPERVISOR_REJECT, StaffLivingWaterMd::STATUS_NEW_SUPERVISOR_APPROVED, StaffLivingWaterMd::STATUS_NEW_SUPERVISOR_REJECT, StaffLivingWaterMd::STATUS_CANCEL, StaffLivingWaterMd::STATUS_ADMIN_APPROVED, StaffLivingWaterMd::STATUS_ADMIN_REJECT];
177→            }
178→        }
179→        $sql = $this->getQuery($input);
180→
181→        if (!$isAdmin) {
182→            if ($isChecked) {
183→                $sql->leftJoin('staff_life_action as sla', 'sla.table_id', '=', 'st.id')->where('sla.user_id', '=', $userId)->where('sla.type', '=', StaffLifeType::TYPE_LIVING_WATER)->where('sla.operate', '=', 1);
184→            } else {
185→                $sql->leftJoin('staff_life_action as sla', 'sla.table_id', '=', 'st.id')->where('sla.user_id', '=', $userId)->where('sla.type', '=', StaffLifeType::TYPE_LIVING_WATER)->where('sla.operate', '=', 0);
186→            }
187→        }
188→        if ($isAdmin) {
189→            $res = $sql->selectRaw('st.*, si.nickname, si.status as staff_status')->distinct()->orderByDesc('st.id')->paginate($input['per_page'] ?? 50)->toArray();
190→            $this->setEmail($res['data']);
191→            return [
192→                'list' => $res['data'],
193→                'current_page' => $res['current_page'],
194→                'per_page' => $res['per_page'],
195→                'total' => $res['total'],
196→            ];
197→        }
198→        $res = $sql->where('st.created_at', '>=', date('Y-m-d H:i:s', strtotime('-30 days')))
199→            ->whereRaw("( st.original_supervisor={$userId} or st.supervisor={$userId} )")
200→            ->selectRaw('st.*, si.nickname, si.entry_time, si.status as staff_status')->distinct()->orderByDesc('st.id')->get()->toArray();
201→        $tokens = [];
202→        $res = array_values(array_filter($res, function ($r) use ($userId, &$tokens) {
203→            $token = getAuthorityToken($userId, $r['staff_id'], 'staff');
204→            $tokens[] = $token;
205→            return $token !== null;
206→        }));
207→        $tokens = array_values(array_unique(array_filter($tokens)));
208→        $this->setEmail($res);
209→        return ['list' => $res, 'decrypt_config' => ['tokens' => $tokens]];
210→    }
