212→    // 处理活水申请
213→    public function dealLivingWater(array $input): array
214→    {
215→        $operate = $input['operate'];
216→        // 获取记录
217→        $staffLivingWater = StaffLivingWaterMd::find($input['living_water_id']);
218→        if ($staffLivingWater == null) {
219→            return ['flag' => false, 'message' => __('my_api.data_not_found')];
220→        }
221→//        if ($operate == 'admin_approve' && empty($input['id_sign'])) {
222→//            return ['flag' => false, 'message' => __('my_api.param_error')];
223→//        }
224→        $statusOperateMap = [
225→            StaffLivingWaterMd::STATUS_WAIT_ORIGINAL_SUPERVISOR_APPROVE => ['original_supervisor_approve', 'original_supervisor_reject', 'cancel'],
226→            StaffLivingWaterMd::STATUS_ORIGINAL_SUPERVISOR_APPROVED => ['new_supervisor_approve', 'new_supervisor_reject', 'cancel'],
227→            StaffLivingWaterMd::STATUS_NEW_SUPERVISOR_APPROVED => ['admin_approve', 'admin_reject', 'cancel'],
228→            StaffLivingWaterMd::STATUS_ORIGINAL_SUPERVISOR_REJECT => [],
229→            StaffLivingWaterMd::STATUS_NEW_SUPERVISOR_REJECT => [],
230→            StaffLivingWaterMd::STATUS_ADMIN_REJECT => [],
231→            StaffLivingWaterMd::STATUS_CANCEL => [],
232→        ];
233→        if (!in_array($operate, StaffLivingWaterMd::OPERATIONS) || !in_array($operate, $statusOperateMap[$staffLivingWater->approval_status])) {
234→            return ['flag' => false, 'message' => __('my_api.operate_not_allowed')];
235→        }
236→        $operateStatusMap = [
237→            'original_supervisor_approve' => [
238→                'approval_status' => [StaffLivingWaterMd::STATUS_WAIT_ORIGINAL_SUPERVISOR_APPROVE => StaffLivingWaterMd::STATUS_ORIGINAL_SUPERVISOR_APPROVED],
239→                'check' => ['checkOriginalSupervisor'],
240→            ],
241→            'original_supervisor_reject' => [
242→                'approval_status' => [StaffLivingWaterMd::STATUS_WAIT_ORIGINAL_SUPERVISOR_APPROVE => StaffLivingWaterMd::STATUS_ORIGINAL_SUPERVISOR_REJECT],
243→                'check' => ['checkOriginalSupervisor'],
244→            ],
245→            'cancel' => [
246→                'approval_status' => [
247→                    StaffLivingWaterMd::STATUS_WAIT_ORIGINAL_SUPERVISOR_APPROVE => StaffLivingWaterMd::STATUS_CANCEL,
248→                    StaffLivingWaterMd::STATUS_ORIGINAL_SUPERVISOR_APPROVED => StaffLivingWaterMd::STATUS_CANCEL,
249→                    StaffLivingWaterMd::STATUS_NEW_SUPERVISOR_APPROVED => StaffLivingWaterMd::STATUS_CANCEL,
250→                ],
251→                'check' => ['checkBp'],
252→            ],
253→            'new_supervisor_approve' => [
254→                'approval_status' => [StaffLivingWaterMd::STATUS_ORIGINAL_SUPERVISOR_APPROVED => StaffLivingWaterMd::STATUS_NEW_SUPERVISOR_APPROVED],
255→                'check' => ['checkNewSupervisor'],
256→            ],
257→            'new_supervisor_reject' => [
258→                'approval_status' => [StaffLivingWaterMd::STATUS_ORIGINAL_SUPERVISOR_APPROVED => StaffLivingWaterMd::STATUS_NEW_SUPERVISOR_REJECT],
259→                'check' => ['checkNewSupervisor'],
260→            ],
261→            'admin_reject' => [
262→                'approval_status' => [StaffLivingWaterMd::STATUS_NEW_SUPERVISOR_APPROVED => StaffLivingWaterMd::STATUS_ADMIN_REJECT],
263→                'check' => ['checkAdmin'],
264→            ],
265→            'admin_approve' => [
266→                'approval_status' => [StaffLivingWaterMd::STATUS_NEW_SUPERVISOR_APPROVED => StaffLivingWaterMd::STATUS_ADMIN_APPROVED],
267→                'check' => ['checkAdmin'],
268→            ],
269→        ];
270→        $checks = $operateStatusMap[$input['operate']]['check'] ?? [];
271→        $checkFlag = true;
272→        if (!empty($checks)) {
273→            foreach ($checks as $v) {
274→                $checkFlag = call_user_func(['self', $v], $staffLivingWater);
275→                if (!$checkFlag) {
276→                    break;
277→                }
278→            }
279→        }
280→        if (!$checkFlag) {
281→            return ['flag' => false, 'message' => __('my_api.operate_not_allowed').'3'];
282→        }
283→        $newApprovalStatus = $operateStatusMap[$input['operate']]['approval_status'][$staffLivingWater->approval_status] ?? 0;
284→        $operateMsg = match ($input['operate']) {
285→            'original_supervisor_approve' => '原主管通过活水申请',
286→            'original_supervisor_reject' => '原主管驳回活水申请',
287→            'cancel' => '取消活水申请',
288→            'new_supervisor_approve' => '新主管通过活水申请',
289→            'new_supervisor_reject' => '新主管驳回活水申请',
290→            'admin_reject' => '管理员驳回活水申请',
291→            'admin_approve' => '管理员通过活水申请',
292→            'staff_approve' => '员工同意活水申请',
293→            'staff_reject' => '员工拒绝活水申请',
294→            default => '活水申请未知操作',
295→        };
296→
297→        $operationRecord2 = '';
298→        $staff = StaffInformationMd::find($staffLivingWater->staff_id);
299→        if ($input['operate'] == 'admin_approve') {
