510→    public function setEmail(&$data): void
511→    {
512→        // 从查询结果中提取 living_water_ids
513→        $livingWaterIds = collect($data)->pluck('id')->unique()->all();
514→
515→        // 基于提取的 living_water_ids 查询 LivingWaterMailMd
516→        $livingWaterMails = LivingWaterMailMd::whereIn('living_water_id', $livingWaterIds)->get();
517→
518→        // 将查询得到的 LivingWaterMail 记录转换为以 living_water_id 为 key 的数组
519→        $livingWaterMailsGroupedByLivingWaterId = [];
520→        foreach ($livingWaterMails as $mail) {
521→            $livingWaterMailsGroupedByLivingWaterId[$mail->living_water_id][] = $mail->toArray();
522→        }
523→
524→        // 将相关的 LivingWaterMail 数据添加到原始查询结果中
525→        foreach ($data as &$item) {
526→            // 默认情况下，假设没有对应的 LivingWaterMail 数据
527→            $item['template_id'] = 0;
528→
529→            // 如果存在相关的 LivingWaterMail 数据，将其添加到当前项
530→            if (isset($livingWaterMailsGroupedByLivingWaterId[$item['id']])) {
531→                $item['template_id'] = $livingWaterMailsGroupedByLivingWaterId[$item['id']][0]['mail']['template_id'] ?? 0;
532→            }
533→        }
534→        unset($item); // 引用变量在循环结束后务必进行解除
535→        // 此时 $data 包含了 enriched 的数据，可以继续使用或返回给前端
536→        // 注意：函数定义中不直接操作 $res，因此无需返回；$data 通过引用传递，所以外部的 $data 已经被更新
537→    }
