 6→
 7→class ExpireTransferRequestJob extends MyJob
 8→{
 9→    /**
10→     * Create a new job instance.
11→     *
12→     * @return void
13→     */
14→    public function __construct()
15→    {
16→    }
17→
18→    /**
19→     * Execute the job.
20→     *
21→     * @return void
22→     */
23→    public function handle()
24→    {
25→        // 获取过期状态的transfer, 判断是否要改成拒绝状态
26→        $this->handleRejectTransfer();
27→        // 获取待员工确认的transfer
28→        $this->handleExpiredTransfer();
29→    }
30→
31→    /**
32→     * @return void
33→     */
34→    private function handleExpiredTransfer(): void
35→    {
36→        $list = StaffTransferMd::where('approval_status', StaffTransferMd::STATUS_ADMIN_APPROVED)->select(['id', 'end_timestamp'])->get()->toArray();
37→        if (empty($list)) {
38→            return;
39→        }
40→        $expiredIds = [];
41→        $nowTime = time();
42→        foreach ($list as $v) {
43→            if ($nowTime >= (int)$v['end_timestamp']) {
44→                $expiredIds[] = $v['id'];
45→            }
46→        }
47→        if (!empty($expiredIds)) {
48→            StaffTransferMd::whereIn('id', $expiredIds)->update(['approval_status' => StaffTransferMd::STATUS_EXPIRED]);
49→        }
50→    }
51→
52→    /**
53→     * @return void
54→     */
55→    private function handleRejectTransfer(): void
56→    {
57→        $expiredList = StaffTransferMd::where('approval_status', StaffTransferMd::STATUS_EXPIRED)->select(['id', 'end_timestamp'])->get()->toArray();
58→        if (empty($expiredList)) {
59→            return;
60→        }
61→        $rejectIds = [];
62→        $nowTime = time();
63→        foreach ($expiredList as $v) {
64→            // 10 days
65→            $rejectTimeStamp = (int)$v['end_timestamp'] + 864000;
66→            if ($nowTime >= $rejectTimeStamp) {
67→                $rejectIds[] = $v['id'];
68→            }
69→        }
70→        if (!empty($rejectIds)) {
71→            StaffTransferMd::whereIn('id', $rejectIds)->update(['approval_status' => StaffTransferMd::STATUS_STAFF_REJECT]);
72→        }
73→    }
74→}
