522→/**
523→ * 获取授权token.
524→ *
525→ * @param array|int|string $authorizedPerson
526→ * @param array|int|string $item
527→ * @param string $type
528→ * @return null|string
529→ */
530→function getAuthorityToken($authorizedPerson, $item, string $type = 'resume'): ?string
531→{
532→    $time = now()->format('Y-m-d H:i:s');
533→
534→    $authorizedPersonSearch = is_array($authorizedPerson) ? ($authorizedPerson[0] ?? []) : $authorizedPerson;
535→    $itemSearch = is_array($item) ? $item[0] : $item;
536→
537→    is_string($authorizedPersonSearch) && $authorizedPersonSearch = "\"{$authorizedPersonSearch}\"";
538→    is_string($itemSearch) && $itemSearch = "'{$itemSearch}'";
539→    $token = AuthorityTokenMd::when($authorizedPersonSearch !== [], function ($query) use ($authorizedPersonSearch) {
540→        $query->where('authorized_person', 'REGEXP', "(\\[|,){$authorizedPersonSearch}(\\]|,)");
541→    })
542→        ->where('item', 'REGEXP', "(\\[|,){$itemSearch}(\\]|,)")
543→        ->whereRaw("expire_time >= TIMESTAMPDIFF(SECOND,created_at,'{$time}')")
544→        ->where('type', $type)
545→        ->select('token', 'authorized_person', 'item')
546→        ->orderBy('id', 'desc')->get()->toArray();
547→    is_array($authorizedPerson) && $token = array_filter($token, function ($value) use ($authorizedPerson) {
548→        if (empty(array_diff($authorizedPerson, $value['authorized_person']))) {
549→            return true;
550→        }
551→        return false;
552→    });
553→
554→    is_array($item) && $token = array_filter($token, function ($value) use ($item) {
555→        if (empty(array_diff($item, $value['item']))) {
556→            return true;
557→        }
558→        return false;
559→    });
560→
561→    $token = array_values($token);
562→    if (!empty($token)) {
563→        return $token[0]['token'];
564→    }
565→
566→    return null;
567→}
